import React from 'react';
import { Lightbulb, Wrench, Home, Zap, Settings, Thermometer, Construction, PenTool, PlusSquare } from 'lucide-react';

const iconMap = {
  "House Wiring": <Home className="text-yellow-500" />,
  "Fan & Light Fitting": <Lightbulb className="text-yellow-500" />,
  "Switch Board Repair": <Settings className="text-yellow-500" />,
  "Inverter & Meter Work": <Zap className="text-yellow-500" />,
  "Cooler & AC Repair": <Thermometer className="text-yellow-500" />,
  "Kitchen Appliances": <Wrench className="text-yellow-500" />,
  "1BHK/2BHK Wiring": <Construction className="text-yellow-500" />,
  "Industrial Fitting": <PenTool className="text-yellow-500" />,
};

const Services = ({ services }) => {
  return (
    <section className="py-20">
      <div className="text-center mb-16">
        <h2 className="text-4xl font-bold mb-4">Our <span className="text-yellow-500">Professional Services</span></h2>
        <div className="w-24 h-1 bg-yellow-500 mx-auto"></div>
        <p className="mt-6 text-gray-400 max-w-2xl mx-auto">
          Expert solutions for all your electrical requirements. Managed by Sohail Mulani.
        </p>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {services.map((service, index) => (
          <div
            key={service.id || index}
            className="glass p-6 rounded-2xl hover:bg-white/5 transition-all group border border-white/5 hover:border-yellow-500/30"
          >
            <div className="w-12 h-12 rounded-xl bg-yellow-500/10 flex items-center justify-center mb-4 group-hover:bg-yellow-500/20 transition-colors">
              {iconMap[service.title] || <PlusSquare className="text-yellow-500" />}
            </div>
            <h3 className="text-xl font-bold mb-2">{service.title}</h3>
            <p className="text-sm text-gray-400 leading-relaxed">
              {service.description || "High-quality electrical work with professional finishing and safety assurance."}
            </p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Services;
